#include <bits/stdc++.h>
using namespace std;
struct node{
	int data,nxt;
}a[100005];
int id[1000005];//id[a[i].data]=i 
int main(){
	a[0].data=0;
	a[1]={1,0};
	id[1]=1;
	int q;
	cin>>q;
	for(int i=2;i<=q+1;i++){
		int op,x;
		cin>>op>>x;
		if(op==1){
			int y;
			cin>>y;
			if(id[x])
				a[i]={y,a[id[x]].nxt},id[y]=i,a[id[x]].nxt=i;
		}else if(op==2 && id[x]){
			cout<<a[a[id[x]].nxt].data<<'\n';
		}else{
			if(a[id[x]].nxt!=0 && id[x])id[a[a[id[x]].nxt].data]=0,a[id[x]].nxt=a[a[id[x]].nxt].nxt;
		}
		/*int p=1;
		while(p!=0){
			cout<<a[p].data<<' ';
			p=a[p].nxt;
		}
		cout<<endl;*/
	}
	return 0;
}
